//! Section type ids, contracts, and codecs.
//!
//! The registry defines what each `type_id` means: class, schema, column
//! classes, sort key, and collection semantics. Each type is a struct with
//! `#[derive(Section)]` (`kronika-derive`), which generates its contract and
//! Parquet codec; this crate owns the shared codec runtime and a linter that
//! checks the contract invariants.
//!
//! See the crate README for the `type_id` scheme, the contract model, the
//! registry linter, and the snapshot-section format.

// The codec generated by `#[derive(Section)]` refers to this crate by name,
// so it must be nameable from inside the crate too.
extern crate self as kronika_registry;

mod codec;
mod contract;
mod type_id;

pub use codec::bgwriter_checkpointer;
pub use codec::{
    CodecError, MAX_ROW_GROUPS, MAX_SECTION_BYTES, MAX_SECTION_ROWS, arrow_schema, decode_section,
    encode_section, nullable_bool, nullable_column, opt_bool, opt_primitive, required_bool,
    required_column, write_bool, write_bool_nullable, write_nullable, write_required,
};
pub use contract::{Column, ColumnClass, ColumnType, LintError, Semantics, TypeContract, lint};
pub use kronika_derive::Section;
pub use type_id::{SectionClass, TypeId};

// Arrow primitive type tokens that `#[derive(Section)]` names in generated
// codecs, re-exported so a type module needs only this crate in scope.
pub use arrow_array::types::{
    Float32Type, Float64Type, Int8Type, Int16Type, Int32Type, Int64Type, UInt8Type, UInt16Type,
    UInt32Type, UInt64Type,
};

/// Every type id known to this build, in registry order.
///
/// Retired types stay here marked [`TypeContract::deprecated`]; ids are never
/// reused.
#[must_use]
pub const fn registry() -> &'static [TypeContract] {
    &[bgwriter_checkpointer::BgwriterCheckpointer::CONTRACT]
}

/// Run the registry linter over every known type.
///
/// # Errors
///
/// Returns the [`LintError`]s found; this is the check wired into CI
/// (README.md, "Registry Linter").
pub fn lint_registry() -> Result<(), Vec<LintError>> {
    lint(registry())
}

#[cfg(test)]
mod tests {
    use super::{lint_registry, registry};

    #[test]
    fn the_registry_is_clean() {
        assert_eq!(lint_registry(), Ok(()));
    }

    #[test]
    fn registry_is_not_empty() {
        assert!(!registry().is_empty());
    }
}
